const data = $input.all()[0].json;
const events = data.items || [];
return [{ json: { events, count: events.length } }];

const SYNC_TAG_BT = 'n8n-calendar-sync';
const SYNC_TAG_ICE = 'n8n-calendar-sync-iceberg';
const REVOPS_CAL = 'joe%40revopsinflection.com';
const BT_CAL = 'joe.ort-contractor%40blackthorn.io';
const ICE_CAL = 'jort%40icebergops.com';
const REVOPS_EMAIL = 'joe@revopsinflection.com';
const BT_EMAIL = 'joe.ort-contractor@blackthorn.io';
const ICE_EMAIL = 'jort@icebergops.com';

const revopsEvents = $('Agg RevOps').first().json.events || [];
const btEvents = $('Agg Blackthorn').first().json.events || [];
const iceEvents = $('Agg Iceberg').first().json.events || [];

const revopsReal = revopsEvents.filter(e =>
  e.extendedProperties?.private?.syncSource !== SYNC_TAG_BT &&
  e.extendedProperties?.private?.syncSource !== SYNC_TAG_ICE
);
const btReal = btEvents.filter(e => e.extendedProperties?.private?.syncSource !== SYNC_TAG_BT);
const iceReal = iceEvents.filter(e => e.extendedProperties?.private?.syncSource !== SYNC_TAG_ICE);

const btSynced = btEvents.filter(e => e.extendedProperties?.private?.syncSource === SYNC_TAG_BT);
const iceSynced = iceEvents.filter(e => e.extendedProperties?.private?.syncSource === SYNC_TAG_ICE);
const revopsBtSynced = revopsEvents.filter(e => e.extendedProperties?.private?.syncSource === SYNC_TAG_BT);
const revopsIceSynced = revopsEvents.filter(e => e.extendedProperties?.private?.syncSource === SYNC_TAG_ICE);

function buildMap(events, actions, calId, cred) {
  const map = new Map();
  for (const e of events) {
    const srcId = e.extendedProperties?.private?.syncSourceId;
    if (!srcId) continue;
    if (map.has(srcId)) {
      const prev = map.get(srcId);
      const keepNew = new Date(e.updated || 0) >= new Date(prev.updated || 0);
      const toDelete = keepNew ? prev : e;
      if (keepNew) map.set(srcId, e);
      actions.push({ calId, cred, method: 'DELETE', eventId: toDelete.id, body: null });
    } else {
      map.set(srcId, e);
    }
  }
  return map;
}

function getAttendees(e) {
  return (e.attendees || []).map(a => (a.email || '').toLowerCase());
}

// Normalize to UTC for timezone-safe time comparison
function toUTC(dt) {
  return dt ? new Date(dt).toISOString() : '';
}
function timeKey(e) {
  return toUTC(e.start?.dateTime) + '|' + toUTC(e.end?.dateTime);
}

// Build busy-time sets for each calendar's real events (for overlap skip check)
const btBusyTimes = new Set(btReal.filter(e => e.start?.dateTime).map(timeKey));
const iceBusyTimes = new Set(iceReal.filter(e => e.start?.dateTime).map(timeKey));

const actions = [];
const btMap = buildMap(btSynced, actions, BT_CAL, 'blackthorn');
const iceMap = buildMap(iceSynced, actions, ICE_CAL, 'iceberg');
const revopsBtMap = buildMap(revopsBtSynced, actions, REVOPS_CAL, 'revops');
const revopsIceMap = buildMap(revopsIceSynced, actions, REVOPS_CAL, 'revops');

// 1. RevOps real -> Blackthorn [Blocked] Busy
for (const e of revopsReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(BT_EMAIL)) { btMap.delete(e.id); continue; }
  // Skip if BT already has a real event at this exact time (let orphan cleanup remove any stale block)
  if (btBusyTimes.has(timeKey(e))) continue;
  const existing = btMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime) {
      actions.push({ calId: BT_CAL, cred: 'blackthorn', method: 'PATCH', eventId: existing.id,
        body: { start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    btMap.delete(e.id);
  } else {
    actions.push({ calId: BT_CAL, cred: 'blackthorn', method: 'POST',
      body: { summary: '[Blocked] Busy', start: e.start, end: e.end,
        transparency: 'opaque', visibility: 'private',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_BT, syncSourceId: e.id } } } });
  }
}

// 2. RevOps real -> Iceberg [Blocked] Busy
for (const e of revopsReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(ICE_EMAIL)) { iceMap.delete(e.id); continue; }
  // Skip if Iceberg already has a real event at this exact time
  if (iceBusyTimes.has(timeKey(e))) continue;
  const existing = iceMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime) {
      actions.push({ calId: ICE_CAL, cred: 'iceberg', method: 'PATCH', eventId: existing.id,
        body: { start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    iceMap.delete(e.id);
  } else {
    actions.push({ calId: ICE_CAL, cred: 'iceberg', method: 'POST',
      body: { summary: '[Blocked] Busy', start: e.start, end: e.end,
        transparency: 'opaque', visibility: 'private',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_ICE, syncSourceId: e.id } } } });
  }
}

// 3. Blackthorn real -> RevOps [Blackthorn] EventName
for (const e of btReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(REVOPS_EMAIL)) { revopsBtMap.delete(e.id); continue; }
  const expectedSummary = '[Blackthorn] ' + (e.summary || 'Untitled');
  const existing = revopsBtMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime || existing.summary !== expectedSummary) {
      actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'PATCH', eventId: existing.id,
        body: { summary: expectedSummary, start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    revopsBtMap.delete(e.id);
  } else {
    actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'POST',
      body: { summary: expectedSummary, start: e.start, end: e.end, transparency: 'opaque',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_BT, syncSourceId: e.id } } } });
  }
}

// 4. Blackthorn real -> Iceberg [Blocked] Busy
for (const e of btReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(ICE_EMAIL)) { iceMap.delete(e.id); continue; }
  // Skip if Iceberg already has a real event at this exact time
  if (iceBusyTimes.has(timeKey(e))) continue;
  const existing = iceMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime) {
      actions.push({ calId: ICE_CAL, cred: 'iceberg', method: 'PATCH', eventId: existing.id,
        body: { start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    iceMap.delete(e.id);
  } else {
    actions.push({ calId: ICE_CAL, cred: 'iceberg', method: 'POST',
      body: { summary: '[Blocked] Busy', start: e.start, end: e.end,
        transparency: 'opaque', visibility: 'private',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_ICE, syncSourceId: e.id } } } });
  }
}

// 5. Iceberg real -> RevOps [Iceberg] EventName
for (const e of iceReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(REVOPS_EMAIL)) { revopsIceMap.delete(e.id); continue; }
  const expectedSummary = '[Iceberg] ' + (e.summary || 'Untitled');
  const existing = revopsIceMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime || existing.summary !== expectedSummary) {
      actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'PATCH', eventId: existing.id,
        body: { summary: expectedSummary, start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    revopsIceMap.delete(e.id);
  } else {
    actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'POST',
      body: { summary: expectedSummary, start: e.start, end: e.end, transparency: 'opaque',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_ICE, syncSourceId: e.id } } } });
  }
}

// 6. Iceberg real -> Blackthorn [Blocked] Busy
for (const e of iceReal) {
  if (!e.start?.dateTime || e.status === 'cancelled') continue;
  if (getAttendees(e).includes(BT_EMAIL)) { btMap.delete(e.id); continue; }
  // Skip if BT already has a real event at this exact time
  if (btBusyTimes.has(timeKey(e))) continue;
  const existing = btMap.get(e.id);
  if (existing) {
    if (existing.start?.dateTime !== e.start?.dateTime || existing.end?.dateTime !== e.end?.dateTime) {
      actions.push({ calId: BT_CAL, cred: 'blackthorn', method: 'PATCH', eventId: existing.id,
        body: { start: e.start, end: e.end, reminders: { useDefault: false, overrides: [] } } });
    }
    btMap.delete(e.id);
  } else {
    actions.push({ calId: BT_CAL, cred: 'blackthorn', method: 'POST',
      body: { summary: '[Blocked] Busy', start: e.start, end: e.end,
        transparency: 'opaque', visibility: 'private',
        reminders: { useDefault: false, overrides: [] },
        extendedProperties: { private: { syncSource: SYNC_TAG_BT, syncSourceId: e.id } } } });
  }
}

// 7. Orphan cleanup — delete remaining map entries (source event no longer exists)
for (const [, e] of btMap) {
  actions.push({ calId: BT_CAL, cred: 'blackthorn', method: 'DELETE', eventId: e.id, body: null });
}
for (const [, e] of iceMap) {
  actions.push({ calId: ICE_CAL, cred: 'iceberg', method: 'DELETE', eventId: e.id, body: null });
}
for (const [, e] of revopsBtMap) {
  actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'DELETE', eventId: e.id, body: null });
}
for (const [, e] of revopsIceMap) {
  actions.push({ calId: REVOPS_CAL, cred: 'revops', method: 'DELETE', eventId: e.id, body: null });
}

if (actions.length === 0) {
  return [{ json: { credential: 'none', method: 'NONE', url: '', body: '{}', stats: 'No sync actions needed' } }];
}

// Dedup ALL POST actions by [calId, start, end, summary] — covers both [Blocked] Busy blocks
// and named events like [Blackthorn] X, preventing ghost recurring instance duplicates
const seenPosts = new Set();
const dedupedActions = [];
for (const a of actions) {
  if (a.method === 'POST' && a.body) {
    const key = a.calId + '|' + toUTC(a.body.start?.dateTime) + '|' + toUTC(a.body.end?.dateTime) + '|' + (a.body.summary || '');
    if (seenPosts.has(key)) continue;
    seenPosts.add(key);
  }
  dedupedActions.push(a);
}

const BASE = 'https://www.googleapis.com/calendar/v3/calendars/';
return dedupedActions.map(a => ({
  json: {
    credential: a.cred,
    method: a.method,
    url: BASE + a.calId + '/events' + (a.eventId ? '/' + a.eventId : '') + '?sendUpdates=none',
    body: a.body ? JSON.stringify(a.body) : '{}'
  }
}));

const items = $input.all();
const timestamp = new Date().toISOString();
const total = items.length;
const errors = items.filter(i => i.json.error || (i.json.statusCode && i.json.statusCode >= 400)).length;
const noAction = items.some(i => i.json.stats === 'No sync actions needed');
return [{ json: { status: 'complete', timestamp, totalActions: noAction ? 0 : total, errors } }];
